                'fa-solid fa-book-open-reader',
                { id: 'reading-verbal', title: 'Okuma & Dil' }
            );
            setIsSaved(true);
            alert("Etkinlik başarıyla arşivlendi.");
        } catch (e) {
            console.error(e);
            alert("Kaydetme sırasında bir hata oluştu.");
        } finally {
            setIsSaving(false);
        }
    };

