const FOOTER_HEIGHT = 50;
const PROBLEM_SECTION_HEIGHT = 450; // Approx height for 3-4 word problems
const OPERATION_ROW_HEIGHT = 100; // Height of one row of operations including gap

export const MathStudio: React.FC<{ onBack: () => void }> = ({ onBack }) => {
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isSaved, setIsSaved] = useState(false);
    const [isShareModalOpen, setIsShareModalOpen] = useState(false);
    const [mode, setMode] = useState<'ai' | 'fast'>('fast');

    const [config, setConfig] = useState<MathStudioConfig>({
        gradeLevel: '3. Sınıf', studentName: '',
        operations: ['add', 'sub'], isMixed: true,
        allowCarry: true, allowBorrow: true, allowRemainder: false, findUnknown: false,
        num1Digits: 2, num2Digits: 1, // Default to 2-digit +/- 1-digit
        includeProblems: false, problemCount: 3, problemSteps: 1, problemTopic: 'Market Alışverişi',
        layoutMode: 'standard', itemCount: 0 // 0 means AUTO
    });

    const [data, setData] = useState<MathStudioData | null>(null);

    // --- SMART FILL LOGIC ---
    const calculateAutoItemCount = () => {
        let availableHeight = A4_HEIGHT_PX - HEADER_HEIGHT - FOOTER_HEIGHT - 60; // 60px padding

        if (config.includeProblems) {
            availableHeight -= PROBLEM_SECTION_HEIGHT;
        }

        const rows = Math.floor(availableHeight / OPERATION_ROW_HEIGHT);
        // 4 Columns is standard for vertical operations
        const count = Math.max(4, rows * 4); 
        return count;
    };

    const handleGenerate = async () => {
        setIsLoading(true);
        try {
            // Determine actual count
            const actualCount = config.itemCount > 0 ? config.itemCount : calculateAutoItemCount();

            // Offline Generator for Drill
            const offlineData = generateMathStudioOffline({
                ...config,
                itemCount: actualCount
            });

            // AI Generator for Word Problems
            if (mode === 'ai' && (config.includeProblems)) {
                const aiData = await generateMathProblemsAI(config);
                setData({ ...offlineData, ...aiData, operations: offlineData.operations });
            } else {
                setData(offlineData);
            }
            setIsSaved(false);
        } catch (e) {
            alert("Hata oluştu.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        if (!user || !data) return;
        setIsSaving(true);
        try {
            await worksheetService.saveWorksheet(
                user.id, data.title, ActivityType.MATH_STUDIO, [data], 'fa-solid fa-calculator', { id: 'math', title: 'Matematik' }
            );
            setIsSaved(true);
        } finally { setIsSaving(false); }
    };

    const handlePrint = (action: 'print' | 'download') => {
        printService.generatePdf('#math-canvas', data?.title || 'Matematik', { action });
    };

    return (
        <div className="h-full flex flex-col bg-[#1a1a1d] text-zinc-100 overflow-hidden font-sans">
            {/* Top Bar */}
            <div className="h-14 bg-zinc-900 border-b border-zinc-800 flex justify-between items-center px-4 shrink-0 z-50 shadow-lg">
                <div className="flex items-center gap-3">
                    <button onClick={onBack} className="w-8 h-8 rounded hover:bg-zinc-800 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-arrow-left"></i></button>
                    <span className="font-black text-sm uppercase tracking-widest text-blue-500">MATH Studio <span className="bg-blue-500/20 text-blue-500 px-1 rounded text-[9px] border border-blue-500/50">PRO</span></span>
                </div>
                <div className="flex gap-2">
                    <button onClick={() => handlePrint('download')} className="p-2 hover:bg-zinc-800 rounded"><i className="fa-solid fa-file-pdf"></i></button>
                    <button onClick={() => setIsShareModalOpen(true)} className="p-2 hover:bg-zinc-800 rounded"><i className="fa-solid fa-share-nodes"></i></button>
                    <button onClick={handleSave} disabled={isSaving || isSaved} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${isSaved ? 'bg-green-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                        {isSaving ? <i className="fa-solid fa-spinner fa-spin"></i> : isSaved ? 'Kaydedildi' : 'Arşive Kaydet'}
                    </button>
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
                {/* Sidebar */}
                <div className="w-80 bg-zinc-900 border-r border-zinc-800 flex flex-col shrink-0 overflow-y-auto custom-scrollbar">
                    <div className="p-5 space-y-8">
                        {/* Mode Switch */}
                        <div className="bg-black/40 p-1 rounded-xl flex border border-zinc-800">
                            <button onClick={() => setMode('fast')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'fast' ? 'bg-zinc-800 text-blue-400 shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}>HIZLI (Drill)</button>
                            <button onClick={() => setMode('ai')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'ai' ? 'bg-zinc-800 text-indigo-400 shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}>AI (Karma)</button>
                        </div>

                        {/* Operations */}
                        <section>
                            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-3 block">İşlem Türleri</label>
                            <div className="grid grid-cols-2 gap-2">
                                {[
                                    {id:'add', label:'Toplama', sym:'+'}, 
                                    {id:'sub', label:'Çıkarma', sym:'-'}, 
                                    {id:'mult', label:'Çarpma', sym:'x'}, 
                                    {id:'div', label:'Bölme', sym:'÷'}
                                ].map(op => (
                                    <button 
                                        key={op.id} 
                                        onClick={() => setConfig(prev => ({ ...prev, operations: prev.operations.includes(op.id as any) ? prev.operations.filter(x => x !== op.id) : [...prev.operations, op.id as any] }))}
                                        className={`py-3 px-2 rounded-xl text-xs font-bold border transition-all flex items-center justify-between ${config.operations.includes(op.id as any) ? 'bg-blue-600/10 border-blue-500/50 text-blue-400' : 'bg-zinc-800/50 border-zinc-800 text-zinc-500 hover:bg-zinc-800'}`}
                                    >
                                        <span>{op.label}</span>
                                        <span className="text-lg leading-none opacity-50">{op.sym}</span>
                                    </button>
                                ))}
                            </div>
                        </section>

                        {/* Digit Config (New) */}
                        <section className="space-y-3 p-4 bg-zinc-800/30 rounded-xl border border-zinc-800">
                             <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block">Sayı Basamakları</label>

                             <div className="flex items-center justify-between">
                                 <span className="text-xs text-zinc-400 font-bold">1. Sayı (Üst)</span>
                                 <div className="flex gap-1">
                                     {[1, 2, 3, 4].map(d => (
                                         <button 
                                             key={d}
                                             onClick={() => setConfig({...config, num1Digits: d})}
                                             className={`w-8 h-8 rounded-lg text-xs font-bold transition-all ${config.num1Digits === d ? 'bg-blue-500 text-white' : 'bg-zinc-800 text-zinc-500 hover:bg-zinc-700'}`}
                                         >{d}</button>
                                     ))}
                                 </div>
                             </div>

                             <div className="flex items-center justify-between">
                                 <span className="text-xs text-zinc-400 font-bold">2. Sayı (Alt)</span>
                                 <div className="flex gap-1">
                                     {[1, 2, 3].map(d => (
                                         <button 
                                             key={d}
                                             onClick={() => setConfig({...config, num2Digits: d})}
                                             className={`w-8 h-8 rounded-lg text-xs font-bold transition-all ${config.num2Digits === d ? 'bg-blue-500 text-white' : 'bg-zinc-800 text-zinc-500 hover:bg-zinc-700'}`}
                                         >{d}</button>
                                     ))}
                                 </div>
                             </div>
                        </section>

                        {/* Constraints */}
                        <section className="space-y-2">
                            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block mb-2">Kısıtlamalar</label>
                            {[
                                {k:'allowCarry', l:'Eldeli Toplama'},
                                {k:'allowBorrow', l:'Onluk Bozmalı Çıkarma'},
                                {k:'allowRemainder', l:'Kalanlı Bölme'},
                                {k:'findUnknown', l:'Bilinmeyeni Bul (? + 5 = 10)'}
                            ].map(opt => (
                                <label key={opt.k} className="flex items-center justify-between p-3 rounded-lg bg-zinc-800/50 hover:bg-zinc-800 cursor-pointer border border-transparent hover:border-zinc-700 transition-all">
                                    <span className="text-xs font-medium text-zinc-300">{opt.l}</span>
                                    <input 
                                        type="checkbox" 
                                        checked={(config as any)[opt.k]} 
                                        onChange={e => setConfig({...config, [opt.k]: e.target.checked})} 
                                        className="w-4 h-4 rounded border-zinc-600 bg-zinc-700 text-blue-500 focus:ring-offset-zinc-900" 
                                    />
                                </label>
                            ))}
                        </section>

                        {/* Problems Toggle */}
                        <section className="pt-4 border-t border-zinc-800">
                            <label className="flex items-center justify-between cursor-pointer mb-4">
                                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Sözel Problemler (AI)</span>
                                <div className={`w-10 h-6 rounded-full relative transition-colors ${config.includeProblems ? 'bg-indigo-500' : 'bg-zinc-700'}`}>
                                    <input type="checkbox" checked={config.includeProblems} onChange={e => setConfig({...config, includeProblems: e.target.checked})} className="hidden" />
                                    <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${config.includeProblems ? 'left-5' : 'left-1'}`}></div>
                                </div>
                            </label>

                            {config.includeProblems && (
                                <div className="space-y-3 animate-in slide-in-from-top-2 p-3 bg-indigo-900/20 rounded-xl border border-indigo-500/20">
                                    <input type="text" value={config.problemTopic} onChange={e => setConfig({...config, problemTopic: e.target.value})} className="w-full p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs placeholder-zinc-600" placeholder="Konu: Market, Okul..." />
                                    <div className="flex gap-2">
                                        <select value={config.problemCount} onChange={e => setConfig({...config, problemCount: Number(e.target.value)})} className="flex-1 p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs">
                                            {[2, 3, 4, 5].map(n => <option key={n} value={n}>{n} Soru</option>)}
                                        </select>
                                        <select value={config.problemSteps} onChange={e => setConfig({...config, problemSteps: Number(e.target.value) as any})} className="flex-1 p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs">
                                            {[1, 2, 3].map(n => <option key={n} value={n}>{n} İşlemli</option>)}
                                        </select>
                                    </div>
                                </div>
                            )}
                        </section>

                        <button onClick={handleGenerate} disabled={isLoading} className="w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-black rounded-xl shadow-xl shadow-blue-900/20 transition-all transform active:scale-95 flex items-center justify-center gap-2">
                            {isLoading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
                            SAYFAYI OLUŞTUR
                        </button>
                    </div>
                </div>

                {/* Canvas */}
                <div className="flex-1 bg-zinc-950 overflow-auto p-8 flex justify-center custom-scrollbar">
                    <div id="math-canvas" className="bg-white text-black shadow-2xl origin-top transition-transform duration-300 scale-90" style={{ width: `${A4_WIDTH_PX}px`, minHeight: `${A4_HEIGHT_PX}px`, padding: '20mm', height: 'auto' }}>
                        {data ? (
                            <div className="worksheet-item h-full flex flex-col">
                                <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} />

                                {/* Operations Grid - Dynamic Auto Fill Layout */}
                                <div className="grid grid-cols-4 gap-x-8 gap-y-10 mt-8 mb-8 content-start flex-1">
                                    {data.operations.map((op, i) => (
                                        <div key={i} className="flex flex-col items-end text-3xl font-mono font-bold border-b-4 border-black pb-1 relative pr-4">
                                            <div className={`tracking-widest ${op.unknownPos === 'num1' ? 'text-transparent border-2 border-dashed border-zinc-300 bg-zinc-50 rounded px-2 min-w-[1.5em]' : ''}`}>
                                                {op.num1}
                                            </div>
                                            <div className="flex items-center gap-3 w-full justify-end">
                                                <span className="text-2xl opacity-50 absolute left-0 bottom-2">{op.operator}</span>
                                                <div className={`tracking-widest ${op.unknownPos === 'num2' ? 'text-transparent border-2 border-dashed border-zinc-300 bg-zinc-50 rounded px-2 min-w-[1.5em]' : ''}`}>
                                                    {op.num2}
                                                </div>
                                            </div>
                                            <div className="absolute top-full right-0 w-full pt-2 text-right">
                                                 <span className={`${op.unknownPos === 'ans' ? 'text-zinc-200' : 'text-black'}`}>
                                                     {op.unknownPos === 'ans' ? '?' : op.answer}
                                                 </span>
                                                 {op.remainder !== undefined && op.remainder > 0 && <span className="text-sm ml-2 text-zinc-500">(K:{op.remainder})</span>}
                                            </div>
                                        </div>
                                    ))}
                                </div>

                                {/* Problems Section */}
                                {data.problems.length > 0 && (
                                    <div className="mt-auto border-t-4 border-zinc-200 pt-8 break-inside-avoid">
                                        <h4 className="font-black text-sm mb-6 uppercase tracking-widest text-zinc-400 flex items-center gap-2">
                                            <i className="fa-solid fa-brain"></i> Problem Atölyesi
                                        </h4>
                                        <div className="space-y-8">
                                            {data.problems.map((p, i) => (
                                                <div key={i} className="flex gap-6 items-start">
                                                    <span className="w-8 h-8 rounded-full bg-black text-white flex items-center justify-center font-bold shrink-0">{i+1}</span>
                                                    <div className="flex-1 space-y-4">
                                                        <p className="text-lg font-medium leading-relaxed font-dyslexic">{p.text}</p>
                                                        <div className="h-32 w-full border-2 border-dashed border-zinc-200 rounded-2xl bg-zinc-50 relative p-4">
                                                            <span className="absolute top-2 left-3 text-[10px] text-zinc-400 uppercase font-bold tracking-widest">Çözüm Alanı</span>
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {/* Footer */}
                                <div className="mt-8 pt-4 border-t border-zinc-100 flex justify-between text-[10px] text-zinc-400 uppercase tracking-widest font-bold">
                                    <span>Bursa Disleksi AI</span>
                                    <span>{new Date().toLocaleDateString('tr-TR')}</span>
                                </div>
                            </div>
                        ) : (
                            <div className="h-full flex flex-col items-center justify-center opacity-10 grayscale select-none">
                                <i className="fa-solid fa-calculator text-9xl mb-8"></i>
                                <p className="font-black text-3xl uppercase tracking-[0.5em]">Matematik</p>
                                <p className="text-sm font-bold mt-2">Stüdyosu</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
            <ShareModal isOpen={isShareModalOpen} onClose={() => setIsShareModalOpen(false)} onShare={() => {}} />
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { ActivityType, WorksheetData, Activity, GeneratorOptions, ActivityCategory } from '../types';
import { ACTIVITY_CATEGORIES, ACTIVITIES } from '../constants';
import * as generators from '../services/generators';
import * as offlineGenerators from '../services/offlineGenerators';
import { GeneratorView } from './GeneratorView';
import { statsService } from '../services/statsService';
import { adminService } from '../services/adminService';

interface SidebarProps {
  selectedActivity: ActivityType | null;
  onSelectActivity: (id: ActivityType | null) => void;
  setWorksheetData: (data: WorksheetData) => void;
  setIsLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  isLoading: boolean;
  isSidebarOpen: boolean;
  closeSidebar: () => void;
  onAddToHistory: (activityType: ActivityType, data: WorksheetData) => void;
  isExpanded?: boolean;
  onOpenStudentModal?: () => void;
  studentProfile?: any;
  styleSettings?: any;
  onOpenOCR?: () => void;
  onOpenCurriculum?: () => void;
  onOpenReadingStudio?: () => void;
  onOpenMathStudio?: () => void; // Added Prop
}

const toPascalCase = (str: string): string => {
    return str.toLowerCase().split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join('');
};

const Sidebar: React.FC<SidebarProps> = ({
  isSidebarOpen,
  closeSidebar,
  selectedActivity,
  onSelectActivity,
  setWorksheetData,
  setIsLoading,
  setError,
  isLoading,
  onAddToHistory,
  isExpanded = true,
  onOpenStudentModal,
  studentProfile,
  styleSettings,
  onOpenOCR,
  onOpenCurriculum,
  onOpenReadingStudio,
  onOpenMathStudio // Added Prop
}) => {
  const [openCategoryId, setOpenCategoryId] = useState<string | null>(null);
  const [allActivities, setAllActivities] = useState<Activity[]>(ACTIVITIES);
  const [categories, setCategories] = useState<ActivityCategory[]>(ACTIVITY_CATEGORIES);

  useEffect(() => {
      const loadCustomActivities = async () => {
          try {
              const customActs = await adminService.getAllActivities();

              const mergedActivities = [...ACTIVITIES];
              const customMap = new Map();

              customActs.forEach(ca => {
                  const index = mergedActivities.findIndex(a => a.id === ca.id);
                  if (index !== -1) {
                      mergedActivities[index] = { ...mergedActivities[index], ...ca };
                  } else {
                      mergedActivities.push(ca);
                  }
                  if (ca.category) {
                      customMap.set(ca.category, true);
                  }
              });

              setAllActivities(mergedActivities);

              const updatedCategories = ACTIVITY_CATEGORIES.map(cat => ({ ...cat, activities: [...cat.activities] }));

              mergedActivities.forEach(act => {
                  const catId = act.category || 'others';
                  let category = updatedCategories.find(c => c.id === catId);

                  if (!category) {
                      const title = catId.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
                      category = {
                          id: catId,
                          title: title,
                          description: 'Özel Kategori',
                          icon: 'fa-solid fa-folder-open',
                          activities: [],
                          isCustom: true
                      };
                      updatedCategories.push(category);
                  }

                  if (!category.activities.includes(act.id)) {
                      category.activities.push(act.id);
                  }
              });

              if (!updatedCategories.find(c => c.id === 'others')) {
                  updatedCategories.push({
                      id: 'others',
                      title: 'Diğerleri (Özel)',
                      description: 'Sistem tarafından üretilen özel etkinlikler.',
                      icon: 'fa-solid fa-wand-magic-sparkles',
                      activities: []
                  });
              }

              setCategories(updatedCategories);

          } catch (e) {
              console.error("Failed to load custom activities", e);
          }
      };
      loadCustomActivities();
  }, []);

  const getActivityById = (id: ActivityType | null): Activity | undefined => {
      if (!id) return undefined;
      return allActivities.find(a => a.id === id);
  }

  const handleGenerate = async (options: GeneratorOptions) => {
    if (!selectedActivity) return;
    setIsLoading(true);
    setWorksheetData(null);
    setError(null);
    const currentAct = getActivityById(selectedActivity);
    try {
        let result: WorksheetData | null = null;
        const pascalCaseName = toPascalCase(selectedActivity);
        const generatorFunctionName = `generate${pascalCaseName}FromAI`;
        const offlineGeneratorFunctionName = `generateOffline${pascalCaseName}`;

        const runOfflineGenerator = async () => {
             // @ts-ignore
             const offlineGenerator = (offlineGenerators as any)[offlineGeneratorFunctionName];
             if (offlineGenerator) return await offlineGenerator(options);
             throw new Error(`"${currentAct?.title}" için üretim motoru bulunamadı.`);
        };

        if (options.mode === 'ai') {
            // @ts-ignore
            const onlineGenerator = (generators as any)[generatorFunctionName];
            if (onlineGenerator) {
                try { result = await onlineGenerator(options); } 
                catch (err) { result = await runOfflineGenerator(); }
            } else {
                result = await runOfflineGenerator();
            }
        } else { 
            result = await runOfflineGenerator();
        }

        if (result) {
            const labeledResult = result.map((page: any) => ({
                ...page,
                title: page.title || currentAct?.title || 'Etkinlik'
            }));
            setWorksheetData(labeledResult);
            onAddToHistory(selectedActivity, labeledResult);
            statsService.incrementUsage(selectedActivity).catch(console.error);
        }
    } catch (e: any) {
        console.error("Etkinlik oluşturulurken hata:", e);
        setError(e.message || "Beklenmeyen bir hata oluştu.");
    } finally {
        setIsLoading(false);
    }
  };

  const currentActivity = getActivityById(selectedActivity);
  const categorizedActivities = useMemo(() => {
      return categories.map(category => ({
          ...category,
          items: allActivities.filter(act => category.activities.includes(act.id))
      })).filter(c => c.items.length > 0);
  }, [allActivities, categories]);

  return (
    <aside
      id="tour-sidebar"
      className={`
        fixed inset-y-0 left-0 z-30 
        bg-white/95 dark:bg-zinc-900/95 backdrop-blur-xl
        border-r border-zinc-200 dark:border-zinc-800
        transition-all duration-500 cubic-bezier(0.19, 1, 0.22, 1)
        md:relative md:translate-x-0
        flex flex-col h-full
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full md:shadow-none'} 
        ${isExpanded ? 'w-[300px]' : 'w-[70px]'}
      `}
      aria-label="Etkinlik Menüsü"
    >
        <div className="flex h-full flex-col">
            {currentActivity ? (
                <GeneratorView 
                    activity={currentActivity}
                    onGenerate={handleGenerate}
                    onBack={() => onSelectActivity(null)}
                    isLoading={isLoading}
                    isExpanded={isExpanded}
                    onOpenStudentModal={onOpenStudentModal}
                    studentProfile={studentProfile}
                />
            ) : (
                <>
                <div className="flex-shrink-0 h-[56px] flex items-center justify-between px-3 border-b border-zinc-200/50 dark:border-zinc-800/50 bg-zinc-50/30 dark:bg-zinc-800/30">
                    {isExpanded ? (
                        <div className="relative w-full group">
                            <i className="fa-solid fa-search absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-indigo-500 transition-colors text-[10px]"></i>
                            <input type="text" placeholder="Etkinlik ara..." className="w-full h-8 pl-8 pr-2 bg-white dark:bg-black/20 border border-zinc-200 dark:border-zinc-700 rounded-lg text-[11px] font-semibold text-zinc-700 dark:text-zinc-200 placeholder-zinc-400 outline-none focus:border-indigo-500/50 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"/>
                        </div>
                    ) : (
                        <div className="w-full flex justify-center"><div className="w-8 h-8 bg-indigo-500/10 text-indigo-600 dark:text-indigo-400 rounded-lg flex items-center justify-center"><i className="fa-solid fa-layer-group text-sm"></i></div></div>
                    )}
                    <button onClick={closeSidebar} className="md:hidden ml-2 w-7 h-7 flex items-center justify-center rounded-full hover:bg-zinc-100 dark:hover:bg-zinc-700 text-zinc-500 transition-colors"><i className="fa-solid fa-xmark text-sm"></i></button>
                </div>

                {/* MODUL BUTTONS - VERTICAL STACK */}
                {isExpanded && (
                    <div className="p-3 flex flex-col gap-2 shrink-0 border-b border-zinc-200 dark:border-zinc-800 mb-2 bg-zinc-50/50 dark:bg-black/20">
                        <div className="text-[10px] font-black text-zinc-400 uppercase tracking-widest px-1">Özel Modüller</div>

                        {/* 1. Reading Studio */}
                        {onOpenReadingStudio && (
                            <button onClick={onOpenReadingStudio} className="w-full flex items-center gap-3 p-2 rounded-xl bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 hover:border-rose-300 dark:hover:border-rose-700 hover:bg-rose-50 dark:hover:bg-rose-900/10 transition-all group shadow-sm">
                                <div className="w-8 h-8 rounded-lg bg-rose-100 dark:bg-rose-900/30 text-rose-600 dark:text-rose-400 flex items-center justify-center shrink-0">
                                    <i className="fa-solid fa-book-open-reader"></i>
                                </div>
                                <span className="text-xs font-bold text-zinc-700 dark:text-zinc-200 group-hover:text-rose-700 dark:group-hover:text-rose-300 text-left">Okuma Stüdyosu</span>
                            </button>
                        )}

                        {/* 2. Math Studio */}
                        {onOpenMathStudio && (
                            <button onClick={onOpenMathStudio} className="w-full flex items-center gap-3 p-2 rounded-xl bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 hover:border-blue-300 dark:hover:border-blue-700 hover:bg-blue-50 dark:hover:bg-blue-900/10 transition-all group shadow-sm">
                                <div className="w-8 h-8 rounded-lg bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 flex items-center justify-center shrink-0">
                                    <i className="fa-solid fa-calculator"></i>
                                </div>
                                <span className="text-xs font-bold text-zinc-700 dark:text-zinc-200 group-hover:text-blue-700 dark:group-hover:text-blue-300 text-left">Matematik Stüdyosu</span>
                            </button>
                        )}

                        {/* 3. Plan */}
                        {onOpenCurriculum && (
                             <button onClick={onOpenCurriculum} className="w-full flex items-center gap-3 p-2 rounded-xl bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 hover:border-emerald-300 dark:hover:border-emerald-700 hover:bg-emerald-50 dark:hover:bg-emerald-900/10 transition-all group shadow-sm">
                                <div className="w-8 h-8 rounded-lg bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 flex items-center justify-center shrink-0">
                                    <i className="fa-solid fa-graduation-cap"></i>
                                </div>
                                <span className="text-xs font-bold text-zinc-700 dark:text-zinc-200 group-hover:text-emerald-700 dark:group-hover:text-emerald-300 text-left">Eğitim Planı</span>
                            </button>
                        )}

                        {/* 4. OCR */}
                        {onOpenOCR && (
                             <button onClick={onOpenOCR} className="w-full flex items-center gap-3 p-2 rounded-xl bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 hover:border-indigo-300 dark:hover:border-indigo-700 hover:bg-indigo-50 dark:hover:bg-indigo-900/10 transition-all group shadow-sm">
                                <div className="w-8 h-8 rounded-lg bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 flex items-center justify-center shrink-0">
                                    <i className="fa-solid fa-camera"></i>
                                </div>
                                <span className="text-xs font-bold text-zinc-700 dark:text-zinc-200 group-hover:text-indigo-700 dark:group-hover:text-indigo-300 text-left">OCR Tarayıcı</span>
                            </button>
                        )}
                    </div>
                )}

                <nav className="flex-1 overflow-y-auto px-2 py-1 custom-scrollbar min-h-0 space-y-0.5">
                    {categorizedActivities.map((category) => {
                        const isOpen = openCategoryId === category.id;
                        return (
                            <div key={category.id}>
                                <button
                                    onClick={() => isExpanded && setOpenCategoryId(isOpen ? null : category.id)}
                                    className={`w-full flex items-center gap-2 px-2 py-1.5 rounded-lg transition-all duration-200 group ${!isExpanded ? 'justify-center' : ''} ${isOpen && isExpanded ? 'bg-zinc-800 text-white dark:bg-white dark:text-zinc-900' : 'hover:bg-zinc-100 dark:hover:bg-zinc-800 text-zinc-600 dark:text-zinc-400'}`}
                                    title={!isExpanded ? category.title : undefined}
                                >
                                    <div className={`w-5 h-5 rounded-md flex items-center justify-center text-[10px] transition-all shrink-0 ${isOpen && isExpanded ? 'text-white dark:text-black' : 'text-zinc-500 dark:text-zinc-500'}`}><i className={category.icon}></i></div>
                                    {isExpanded && (
                                        <>
                                            <span className="flex-1 text-left text-[11px] font-bold uppercase tracking-tight truncate">{category.title}</span>
                                            <i className={`fa-solid fa-chevron-down text-[8px] opacity-50 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}></i>
                                        </>
                                    )}
                                </button>
                                {isExpanded && isOpen && (
                                    <div className="overflow-hidden animate-in slide-in-from-left-1 duration-200">
                                        <div className="pl-3 ml-[11px] border-l border-zinc-200 dark:border-zinc-800 mt-0.5 space-y-0.5">
                                            {category.items.map(activity => (
                                                <button key={activity.id} onClick={() => { onSelectActivity(activity.id); if(window.innerWidth < 768) closeSidebar(); }} className={`w-full text-left px-3 py-1 rounded-md text-[10px] font-medium transition-all flex items-center gap-1.5 relative ${selectedActivity === activity.id ? 'bg-indigo-50/50 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-300 font-bold' : 'text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 hover:bg-zinc-50 dark:hover:bg-zinc-800/30'}`}>
                                                    <span className={`w-1 h-1 rounded-full ${selectedActivity === activity.id ? 'bg-indigo-500' : 'bg-transparent border border-zinc-300'}`}></span>
                                                    <span className="truncate">{activity.title}</span>
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </nav>
                </>
            )}
        </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { MathStudioConfig, MathStudioData, ActivityType } from '../../types';
import { generateMathProblemsAI } from '../../services/generators/mathStudio';
import { generateMathStudioOffline } from '../../services/offlineGenerators/mathStudio';
import { useAuth } from '../../context/AuthContext';
import { printService } from '../../utils/printService';
import { worksheetService } from '../../services/worksheetService';
import { PedagogicalHeader } from '../sheets/common';
import { ShareModal } from '../ShareModal';

const A4_WIDTH_PX = 794;
const A4_HEIGHT_PX = 1123;
const HEADER_HEIGHT = 180;
const FOOTER_HEIGHT = 50;
const PROBLEM_SECTION_HEIGHT = 450; 

// Layout Configuration Interface
interface LayoutSettings {
    scale: number;
    columns: number;
    rowGap: number;
    colGap: number;
    fontSize: number;
}

export const MathStudio: React.FC<{ onBack: () => void }> = ({ onBack }) => {
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isSaved, setIsSaved] = useState(false);
    const [isShareModalOpen, setIsShareModalOpen] = useState(false);
    const [mode, setMode] = useState<'ai' | 'fast'>('fast');
    const [activeTab, setActiveTab] = useState<'content' | 'layout'>('content');

    // Content Configuration
    const [config, setConfig] = useState<MathStudioConfig>({
        gradeLevel: '3. Sınıf', studentName: '',
        operations: ['add', 'sub'], isMixed: true,
        allowCarry: true, allowBorrow: true, allowRemainder: false, findUnknown: false,
        num1Digits: 2, num2Digits: 1, 
        includeProblems: false, problemCount: 3, problemSteps: 1, problemTopic: 'Market Alışverişi',
        layoutMode: 'standard', itemCount: 0 
    });

    // Layout Configuration (New)
    const [layout, setLayout] = useState<LayoutSettings>({
        scale: 1,
        columns: 4,
        rowGap: 40,
        colGap: 30,
        fontSize: 24
    });

    const [data, setData] = useState<MathStudioData | null>(null);

    // --- SMART FILL LOGIC ---
    const calculateAutoItemCount = () => {
        let availableHeight = A4_HEIGHT_PX - HEADER_HEIGHT - FOOTER_HEIGHT - 60; 

        if (config.includeProblems) {
            availableHeight -= PROBLEM_SECTION_HEIGHT;
        }

        // Approximate row height based on font size + gap
        const estimatedRowHeight = layout.fontSize * 4 + layout.rowGap; 
        const rows = Math.floor(availableHeight / estimatedRowHeight);
        const count = Math.max(layout.columns, rows * layout.columns); 
        return count;
    };

    const handleGenerate = async () => {
        setIsLoading(true);
        try {
            // Determine actual count
            const actualCount = config.itemCount > 0 ? config.itemCount : calculateAutoItemCount();

            // Offline Generator for Drill
            const offlineData = generateMathStudioOffline({
                ...config,
                itemCount: actualCount
            });

            // AI Generator for Word Problems
            if (mode === 'ai' && (config.includeProblems)) {
                const aiData = await generateMathProblemsAI(config);
                setData({ ...offlineData, ...aiData, operations: offlineData.operations });
            } else {
                setData(offlineData);
            }
            setIsSaved(false);
        } catch (e) {
            alert("Hata oluştu.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        if (!user || !data) return;
        setIsSaving(true);
        try {
            await worksheetService.saveWorksheet(
                user.id, data.title, ActivityType.MATH_STUDIO, [data], 'fa-solid fa-calculator', { id: 'math', title: 'Matematik' }
            );
            setIsSaved(true);
        } finally { setIsSaving(false); }
    };

    const handlePrint = (action: 'print' | 'download') => {
        printService.generatePdf('#math-canvas', data?.title || 'Matematik', { action });
    };

    return (
        <div className="h-full flex flex-col bg-[#1a1a1d] text-zinc-100 overflow-hidden font-sans">
            {/* Top Bar */}
            <div className="h-14 bg-zinc-900 border-b border-zinc-800 flex justify-between items-center px-4 shrink-0 z-50 shadow-lg">
                <div className="flex items-center gap-3">
                    <button onClick={onBack} className="w-8 h-8 rounded hover:bg-zinc-800 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-arrow-left"></i></button>
                    <span className="font-black text-sm uppercase tracking-widest text-blue-500">MATH Studio <span className="bg-blue-500/20 text-blue-500 px-1 rounded text-[9px] border border-blue-500/50">PRO</span></span>
                </div>
                <div className="flex gap-2">
                    <button onClick={() => handlePrint('download')} className="p-2 hover:bg-zinc-800 rounded"><i className="fa-solid fa-file-pdf"></i></button>
                    <button onClick={() => setIsShareModalOpen(true)} className="p-2 hover:bg-zinc-800 rounded"><i className="fa-solid fa-share-nodes"></i></button>
                    <button onClick={handleSave} disabled={isSaving || isSaved} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${isSaved ? 'bg-green-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                        {isSaving ? <i className="fa-solid fa-spinner fa-spin"></i> : isSaved ? 'Kaydedildi' : 'Arşive Kaydet'}
                    </button>
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
                {/* Sidebar */}
                <div className="w-80 bg-zinc-900 border-r border-zinc-800 flex flex-col shrink-0">
                    {/* Tab Header */}
                    <div className="flex border-b border-zinc-800">
                        <button 
                            onClick={() => setActiveTab('content')} 
                            className={`flex-1 py-3 text-xs font-bold uppercase transition-colors ${activeTab === 'content' ? 'text-blue-500 border-b-2 border-blue-500' : 'text-zinc-500 hover:text-zinc-300'}`}
                        >
                            İçerik
                        </button>
                        <button 
                            onClick={() => setActiveTab('layout')} 
                            className={`flex-1 py-3 text-xs font-bold uppercase transition-colors ${activeTab === 'layout' ? 'text-blue-500 border-b-2 border-blue-500' : 'text-zinc-500 hover:text-zinc-300'}`}
                        >
                            Görünüm
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-8">
                        {/* CONTENT TAB */}
                        {activeTab === 'content' && (
                            <>
                                {/* Mode Switch */}
                                <div className="bg-black/40 p-1 rounded-xl flex border border-zinc-800">
                                    <button onClick={() => setMode('fast')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'fast' ? 'bg-zinc-800 text-blue-400 shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}>HIZLI (Drill)</button>
                                    <button onClick={() => setMode('ai')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'ai' ? 'bg-zinc-800 text-indigo-400 shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}>AI (Karma)</button>
                                </div>

                                {/* Operations */}
                                <section>
                                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-3 block">İşlem Türleri</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {[
                                            {id:'add', label:'Toplama', sym:'+'}, 
                                            {id:'sub', label:'Çıkarma', sym:'-'}, 
                                            {id:'mult', label:'Çarpma', sym:'x'}, 
                                            {id:'div', label:'Bölme', sym:'÷'}
                                        ].map(op => (
                                            <button 
                                                key={op.id} 
                                                onClick={() => setConfig(prev => ({ ...prev, operations: prev.operations.includes(op.id as any) ? prev.operations.filter(x => x !== op.id) : [...prev.operations, op.id as any] }))}
                                                className={`py-3 px-2 rounded-xl text-xs font-bold border transition-all flex items-center justify-between ${config.operations.includes(op.id as any) ? 'bg-blue-600/10 border-blue-500/50 text-blue-400' : 'bg-zinc-800/50 border-zinc-800 text-zinc-500 hover:bg-zinc-800'}`}
                                            >
                                                <span>{op.label}</span>
                                                <span className="text-lg leading-none opacity-50">{op.sym}</span>
                                            </button>
                                        ))}
                                    </div>
                                </section>

                                {/* Digit Config */}
                                <section className="space-y-3 p-4 bg-zinc-800/30 rounded-xl border border-zinc-800">
                                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block">Sayı Basamakları</label>

                                    <div className="flex items-center justify-between">
                                        <span className="text-xs text-zinc-400 font-bold">1. Sayı (Üst)</span>
                                        <div className="flex gap-1">
                                            {[1, 2, 3, 4].map(d => (
                                                <button 
                                                    key={d}
                                                    onClick={() => setConfig({...config, num1Digits: d})}
                                                    className={`w-8 h-8 rounded-lg text-xs font-bold transition-all ${config.num1Digits === d ? 'bg-blue-500 text-white' : 'bg-zinc-800 text-zinc-500 hover:bg-zinc-700'}`}
                                                >{d}</button>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="flex items-center justify-between">
                                        <span className="text-xs text-zinc-400 font-bold">2. Sayı (Alt)</span>
                                        <div className="flex gap-1">
                                            {[1, 2, 3].map(d => (
                                                <button 
                                                    key={d}
                                                    onClick={() => setConfig({...config, num2Digits: d})}
                                                    className={`w-8 h-8 rounded-lg text-xs font-bold transition-all ${config.num2Digits === d ? 'bg-blue-500 text-white' : 'bg-zinc-800 text-zinc-500 hover:bg-zinc-700'}`}
                                                >{d}</button>
                                            ))}
                                        </div>
                                    </div>
                                </section>

                                {/* Constraints */}
                                <section className="space-y-2">
                                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block mb-2">Kısıtlamalar</label>
                                    {[
                                        {k:'allowCarry', l:'Eldeli Toplama'},
                                        {k:'allowBorrow', l:'Onluk Bozmalı Çıkarma'},
                                        {k:'allowRemainder', l:'Kalanlı Bölme'},
                                        {k:'findUnknown', l:'Bilinmeyeni Bul (? + 5 = 10)'}
                                    ].map(opt => (
                                        <label key={opt.k} className="flex items-center justify-between p-3 rounded-lg bg-zinc-800/50 hover:bg-zinc-800 cursor-pointer border border-transparent hover:border-zinc-700 transition-all">
                                            <span className="text-xs font-medium text-zinc-300">{opt.l}</span>
                                            <input 
                                                type="checkbox" 
                                                checked={(config as any)[opt.k]} 
                                                onChange={e => setConfig({...config, [opt.k]: e.target.checked})} 
                                                className="w-4 h-4 rounded border-zinc-600 bg-zinc-700 text-blue-500 focus:ring-offset-zinc-900" 
                                            />
                                        </label>
                                    ))}
                                </section>

                                {/* Problems Toggle */}
                                <section className="pt-4 border-t border-zinc-800">
                                    <label className="flex items-center justify-between cursor-pointer mb-4">
                                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Sözel Problemler (AI)</span>
                                        <div className={`w-10 h-6 rounded-full relative transition-colors ${config.includeProblems ? 'bg-indigo-500' : 'bg-zinc-700'}`}>
                                            <input type="checkbox" checked={config.includeProblems} onChange={e => setConfig({...config, includeProblems: e.target.checked})} className="hidden" />
                                            <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${config.includeProblems ? 'left-5' : 'left-1'}`}></div>
                                        </div>
                                    </label>

                                    {config.includeProblems && (
                                        <div className="space-y-3 animate-in slide-in-from-top-2 p-3 bg-indigo-900/20 rounded-xl border border-indigo-500/20">
                                            <input type="text" value={config.problemTopic} onChange={e => setConfig({...config, problemTopic: e.target.value})} className="w-full p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs placeholder-zinc-600" placeholder="Konu: Market, Okul..." />
                                            <div className="flex gap-2">
                                                <select value={config.problemCount} onChange={e => setConfig({...config, problemCount: Number(e.target.value)})} className="flex-1 p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs">
                                                    {[2, 3, 4, 5].map(n => <option key={n} value={n}>{n} Soru</option>)}
                                                </select>
                                                <select value={config.problemSteps} onChange={e => setConfig({...config, problemSteps: Number(e.target.value) as any})} className="flex-1 p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs">
                                                    {[1, 2, 3].map(n => <option key={n} value={n}>{n} İşlemli</option>)}
                                                </select>
                                            </div>
                                        </div>
                                    )}
                                </section>
                            </>
                        )}

                        {/* LAYOUT TAB (NEW) */}
                        {activeTab === 'layout' && (
                            <div className="space-y-6">
                                <div className="p-3 bg-blue-900/20 border border-blue-500/30 rounded-lg text-xs text-blue-200 leading-relaxed">
                                    <i className="fa-solid fa-circle-info mr-1"></i>
                                    Bu ayarlar işlemlerin sayfa üzerindeki yerleşimini ve boyutunu anlık olarak değiştirir.
                                </div>

                                {/* Scale */}
                                <div>
                                    <div className="flex justify-between mb-2">
                                        <label className="text-[10px] font-bold text-zinc-400 uppercase">Sayfa İçi Ölçek (Zoom)</label>
                                        <span className="text-xs font-mono text-zinc-300">{layout.scale}x</span>
                                    </div>
                                    <input 
                                        type="range" min="0.5" max="1.5" step="0.05" 
                                        value={layout.scale} 
                                        onChange={e => setLayout({...layout, scale: parseFloat(e.target.value)})}
                                        className="w-full accent-blue-500"
                                    />
                                </div>

                                {/* Font Size */}
                                <div>
                                    <div className="flex justify-between mb-2">
                                        <label className="text-[10px] font-bold text-zinc-400 uppercase">Yazı Boyutu</label>
                                        <span className="text-xs font-mono text-zinc-300">{layout.fontSize}px</span>
                                    </div>
                                    <input 
                                        type="range" min="16" max="48" step="1" 
                                        value={layout.fontSize} 
                                        onChange={e => setLayout({...layout, fontSize: parseInt(e.target.value)})}
                                        className="w-full accent-blue-500"
                                    />
                                </div>

                                {/* Columns */}
                                <div>
                                    <div className="flex justify-between mb-2">
                                        <label className="text-[10px] font-bold text-zinc-400 uppercase">Sütun Sayısı</label>
                                        <span className="text-xs font-mono text-zinc-300">{layout.columns}</span>
                                    </div>
                                    <input 
                                        type="range" min="2" max="6" step="1" 
                                        value={layout.columns} 
                                        onChange={e => setLayout({...layout, columns: parseInt(e.target.value)})}
                                        className="w-full accent-blue-500"
                                    />
                                </div>

                                {/* Gaps */}
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-[10px] font-bold text-zinc-400 uppercase mb-2 block">Satır Boşluğu</label>
                                        <input 
                                            type="number" 
                                            value={layout.rowGap} 
                                            onChange={e => setLayout({...layout, rowGap: parseInt(e.target.value)})}
                                            className="w-full p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs"
                                        />
                                    </div>
                                    <div>
                                        <label className="text-[10px] font-bold text-zinc-400 uppercase mb-2 block">Sütun Boşluğu</label>
                                        <input 
                                            type="number" 
                                            value={layout.colGap} 
                                            onChange={e => setLayout({...layout, colGap: parseInt(e.target.value)})}
                                            className="w-full p-2 bg-zinc-900 border border-zinc-700 rounded-lg text-xs"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        <button onClick={handleGenerate} disabled={isLoading} className="w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-black rounded-xl shadow-xl shadow-blue-900/20 transition-all transform active:scale-95 flex items-center justify-center gap-2">
                            {isLoading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
                            SAYFAYI OLUŞTUR
                        </button>
                    </div>
                </div>

                {/* Canvas */}
                <div className="flex-1 bg-zinc-950 overflow-auto p-8 flex justify-center custom-scrollbar">
                    <div id="math-canvas" className="bg-white text-black shadow-2xl origin-top transition-transform duration-300 scale-90" style={{ width: `${A4_WIDTH_PX}px`, minHeight: `${A4_HEIGHT_PX}px`, padding: '20mm', height: 'auto' }}>
                        {data ? (
                            <div className="worksheet-item h-full flex flex-col">
                                <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} />

                                {/* Operations Grid - Dynamic Layout */}
