                                        rowGap: `${layout.rowGap}px`,
                                        marginTop: '2rem',
                                        marginBottom: '2rem',
                                        transform: `scale(${layout.scale})`,
                                        transformOrigin: 'top center',
                                        width: '100%'
                                    }}
                                >
                                    {data.operations.map((op, i) => (
                                        <div key={i} className="flex flex-col items-end font-mono font-bold border-b-4 border-black pb-1 relative pr-2 break-inside-avoid" style={{ fontSize: `${layout.fontSize}px`, lineHeight: 1.2 }}>
                                            <div className={`tracking-widest ${op.unknownPos === 'num1' ? 'text-transparent border-2 border-dashed border-zinc-300 bg-zinc-50 rounded px-1 min-w-[1.5em]' : ''}`}>
                                                {op.num1}
                                            </div>
