                                )}

                                {/* Footer */}
                                <div className="mt-8 pt-4 border-t border-zinc-100 flex justify-between text-[10px] text-zinc-400 uppercase tracking-widest font-bold">
                                    <span>Bursa Disleksi AI</span>
